def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Helper to build a clause for a single triple
    def _clause(s: str, p: str, o: str) -> str:
        # Primary airport‑specific predicates
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        # Runway number, surface and length handling via regex
        runway_match = re.fullmatch(r"(\\d+)(st|nd|rd|th)?(Runway)([A-Za-z]+)", p)
        if runway_match:
            num = runway_match.group(1)
            suffix = runway_match.group(2) or ""
            attr = runway_match.group(4).lower()
            # Determine phrasing based on attribute
            if attr.startswith("lengthfeet"):
                length = o
                return f"{s}'s {num}{suffix.lower()} runway is {length} feet long"
            if attr.startswith("lengthmetre"):
                length = o
                return f"{s}'s {num}{suffix.lower()} runway is {length} metres long"
            if attr.startswith("surfacetype"):
                return f"{s}'s {num}{suffix.lower()} runway surface is {attr.replace('surfacetype','').strip() or 'unspecified'} {o}"
            if attr.startswith("number"):
                return f"{s}'s {num}{suffix.lower()} runway number is {o}"
            # generic fallback for numbered runway attributes
            return f"{s}'s {num}{suffix.lower()} runway {attr.replace('surface',' surface').replace('length',' length')} is {o}"
        # Generic runway predicates without number
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        # Runway identifiers
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "runwayLength":
            return f"{s}'s runway length is {o}"
        # Aviation codes
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        # Ownership and administration
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "largestCity":
            return f"The largest city of {s} is {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p in ("language", "officialLanguage"):
            return f"The official language of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The leader title of {s} is {o}"
        if p == "leaderParty":
            return f"The leader of {s} belongs to the {o} party"
        # Additional predicates for regions and governance
        if p == "administrativeArrondissement":
            return f"{s} belongs to the administrative arrondissement {o}"
        if p == "jurisdiction":
            return f"{s} falls under the jurisdiction of {o}"
        if p == "demonym":
            return f"The demonym for {s} is {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p == "regionServed":
            return f"{s} serves the region of {o}"
        if p == "hubAirport":
            return f"{s} uses {o} as a hub airport"
        if p == "headquarter":
            return f"The headquarters of {s} are at {o}"
        if p == "chief":
            return f"The chief of {s} is {o}"
        if p == "foundedBy":
            return f"{s} was founded by {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "postalCode":
            return f"The postal code of {s} is {o}"
        if p == "areaCode":
            return f"The area code of {s} is {o}"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Build clauses
    raw_clauses = [_clause(t.subject, t.predicate, _clean(t.object)) for t in triples]
    clauses = raw_clauses

    # Combine clauses into a single complex sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

